import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';
import { useInView } from 'react-intersection-observer';
import { BrowserRouter as Router, Route, Switch, useHistory, useLocation } from 'react-router-dom';

function shuffleArray(array) {
  for (let i = array.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [array[i], array[j]] = [array[j], array[i]];
  }
  return array;
}

const Video = ({ src, videoID, onVideoClick }) => {
  const { ref, inView } = useInView({
    triggerOnce: true,
    threshold: 0.1,
  });

  return (
    <video
      ref={ref}
      src={src}
      autoPlay
      loop
      muted
      playsInline
      loading="lazy"
      className={inView ? 'fade-in' : ''}
      onClick={() => onVideoClick(videoID)} // Handle click event
    />
  );
};

const Modal = ({ videoInfo, onClose }) => (
  <div className="modal">
    <div className="modal-content">
      <span className="close" onClick={onClose}>&times;</span>
      <pre>{JSON.stringify(videoInfo, null, 2)}</pre>
    </div>
  </div>
);

function App() {
  const [scenes, setScenes] = useState([]);
  const [selectedVideoInfo, setSelectedVideoInfo] = useState(null);
  const history = useHistory();
  const location = useLocation();

  useEffect(() => {
    axios.get('https://fierce-springs-10022-1e7f8f8c4e94.herokuapp.com/videos')
      .then(response => {
        setScenes(shuffleArray(response.data));
      })
      .catch(error => {
        console.error('Error fetching data: ', error);
      });

    // Check URL for videoID and load video info if present
    const videoID = location.pathname.split('/videos/')[1];
    if (videoID) {
      handleVideoClick(videoID);
    }
  }, [location.pathname]);

  function handleVideoClick(videoID) {
    axios.get(`https://fierce-springs-10022-1e7f8f8c4e94.herokuapp.com/video_info/${videoID}`)
      .then(response => {
        setSelectedVideoInfo(response.data);
        history.push(`/videos/${videoID}`); // Update URL
      })
      .catch(error => {
        console.error('Error fetching video info: ', error);
      });
  }

  function handleCloseModal() {
    setSelectedVideoInfo(null);
    history.push('/'); // Reset URL
  }

  return (
    <div className="App">
      <div className="video-grid">
        {scenes.map(scene => (
          <Video
            key={scene.sceneURL}
            src={scene.sceneURL}
            videoID={scene.videoID}
            onVideoClick={handleVideoClick}
          />
        ))}
      </div>
      {selectedVideoInfo && <Modal videoInfo={selectedVideoInfo} onClose={handleCloseModal} />}
    </div>
  );
}

function AppWrapper() {
  return (
    <Router>
      <Switch>
        <Route path="/" component={App} />
      </Switch>
    </Router>
  );
}

export default AppWrapper;
